changeSet.sql:
DROP VIEW IF EXISTS view_riksdagen_election_year_behavioral_patterns CASCADE; DROP MATERIALIZED VIEW IF EXISTS mv_annual_voting_metrics CASCADE;
CREATE MATERIALIZED VIEW mv_annual_voting_metrics AS WITH election_years AS ( SELECT unnest(ARRAY[2002, 2006, 2010, 2014, 2018, 2022, 2026]) AS election_year ) SELECT (EXTRACT(year FROM vd.vote_date))::integer AS year, CASE WHEN ey.election_year IS NOT NULL THEN true ELSE false END AS is_election_year, count(DISTINCT vd.embedded_id_ballot_id) AS total_ballots, count(DISTINCT vd.embedded_id_intressent_id) AS active_politicians, round((avg(CASE WHEN UPPER((vd.vote)::text) <> 'FRÅNVARANDE' THEN 1 ELSE 0 END) * 100::numeric), 2) AS attendance_rate, round((avg(CASE WHEN UPPER((vd.vote)::text) = 'JA' THEN 1 ELSE 0 END) * 100::numeric), 2) AS avg_yes_rate, round((avg(CASE WHEN UPPER((vd.vote)::text) = 'NEJ' THEN 1 ELSE 0 END) * 100::numeric), 2) AS avg_no_rate, round((avg(CASE WHEN UPPER((vd.vote)::text) = 'AVSTÅR' THEN 1 ELSE 0 END) * 100::numeric), 2) AS avg_abstain_rate FROM vote_data vd LEFT JOIN election_years ey ON ey.election_year::numeric = EXTRACT(year FROM vd.vote_date) WHERE vd.vote_date IS NOT NULL AND EXTRACT(year FROM vd.vote_date) >= 2002 AND EXTRACT(year FROM vd.vote_date) <= 2026 GROUP BY (EXTRACT(year FROM vd.vote_date))::integer, CASE WHEN ey.election_year IS NOT NULL THEN true ELSE false END WITH NO DATA;
COMMENT ON MATERIALIZED VIEW mv_annual_voting_metrics IS 'Pre-aggregated annual voting metrics from vote_data (2002-2026). Uses UPPER() for vote comparisons. Refresh: Daily.';
